import re, subprocess, os, itertools, random

APP="/app"
orig=open(f"{APP}/input.tex").read()
fams=[[w.strip() for w in line.split(",")] for line in open(f"{APP}/synonyms.txt") if line.strip()]
word2fam={}
for fam in fams:
    for w in fam:
        word2fam[w.lower()]=fam

geom=r"""\documentclass[letterpaper]{article}
\setlength{\topmargin}{2in}
\setlength{\headheight}{0pt}
\setlength{\headsep}{0pt}
\setlength{\textheight}{5in}
\setlength{\textwidth}{2.5in}
\setlength{\oddsidemargin}{2in}
\setlength{\evensidemargin}{2in}
\setlength{\footskip}{0.5in}
\begin{document}
\input{tinp.tex}
\end{document}
"""
WORK="/tmp/lw"; os.makedirs(WORK,exist_ok=True)
open(f"{WORK}/tmain.tex","w").write(geom)
def overfull(text):
    open(f"{WORK}/tinp.tex","w").write(text)
    subprocess.run(["pdflatex","-interaction=nonstopmode","tmain.tex"],cwd=WORK,
                   stdout=subprocess.DEVNULL,stderr=subprocess.DEVNULL)
    return open(f"{WORK}/tmain.log",errors="ignore").read().count("Overfull \\hbox")

def apply_case(orig, repl):
    if orig[0].isupper():
        return repl[0].upper()+repl[1:]
    return repl

def sites_of(text):
    sites=[]
    for m in re.finditer(r"[A-Za-z]+", text):
        w=m.group(0)
        fam=word2fam.get(w.lower())
        if fam:
            variants=[apply_case(w,v) for v in fam if v.lower()!=w.lower()]
            sites.append((m.start(),m.end(),w,variants))
    return sites

def render(text, sites, assign):
    # assign: dict idx->variant string; build from original text using site spans
    out=[]; last=0
    for i,(s,e,w,vs) in enumerate(sites):
        out.append(text[last:s])
        out.append(assign.get(i,w))
        last=e
    out.append(text[last:])
    return "".join(out)

def solve_para(base):
    if overfull(base)==0: return base,{}
    sites=sites_of(base)
    best_assign={}
    best_of=overfull(base)
    # greedy hill climb with restarts
    for restart in range(40):
        assign=dict(best_assign)  # start from best so far
        if restart>0:
            # random perturbation
            for _ in range(restart% 5 +1):
                i=random.randrange(len(sites))
                vs=sites[i][3]
                assign[i]=random.choice(vs)
        cur=overfull(render(base,sites,assign))
        improved=True
        while improved and cur>0:
            improved=False
            order=list(range(len(sites))); random.shuffle(order)
            for i in order:
                s,e,w,vs=sites[i]
                options=[w]+vs
                for opt in options:
                    trial=dict(assign)
                    if opt==w: trial.pop(i,None)
                    else: trial[i]=opt
                    o=overfull(render(base,sites,trial))
                    if o<cur:
                        cur=o; assign=trial; improved=True
                        break
                if improved: break
            if cur<best_of:
                best_of=cur; best_assign=dict(assign)
        if cur<best_of:
            best_of=cur; best_assign=dict(assign)
        if best_of==0:
            break
    return render(base,sites,best_assign), best_assign, best_of

paras=orig.split("\n\n")
results=[]
for i,p in enumerate(paras):
    of=overfull(p)
    if of==0:
        results.append(p); continue
    newp,assign,bo=solve_para(p)
    print(f"para {i}: {of} -> {bo}")
    results.append(newp)
final="\n\n".join(results)
print("TOTAL overfull:", overfull(final))
open("/tmp/final_input.tex","w").write(final)
